import { useEffect, useLayoutEffect, useRef, useState, useCallback } from "react";
import styles from "./Globe.module.css";

// ─── TYPES ────────────────────────────────────────────────────────────────────

interface MassDefinition {
  label: string;
  img: string;
  desc: string;
  lng: number;
  lat: number;
  scale: number;
  boost: number;
  svg: string;
}

interface Raster {
  imgData: ImageData;
  svgW: number;
  svgH: number;
}

interface Mass extends MassDefinition, Raster {
  centerXYZ: [number, number, number];
  basis: TangentBasis;
}

interface TangentBasis {
  axisE: [number, number, number];
  axisN: [number, number, number];
}

interface DotDatum {
  pt: [number, number, number];
  massIdx: number;
}

interface Callout {
  label: string;
  img: string;
  desc: string;
  /** Raw projected position of the mass center — used as the clamping input */
  anchorX: number;
  anchorY: number;
  /** Clamped render position — written by useLayoutEffect after the element mounts */
  x: number;
  y: number;
}

interface GlobeState {
  W: number;
  H: number;
  R: number;
  rotX: number;
  rotY: number;
  velX: number;
  velY: number;
  dragging: boolean;
  didDrag: boolean;
  lastX: number;
  lastY: number;
  lastT: number;
  pvX: number;
  pvY: number;
  autoSpin: boolean;
  dotData: DotDatum[];
  masses: Mass[];
  ready: boolean;
  rafId: number | null;
  hoveredMassIdx: number;
  activeMassIdx: number;
}

